import React, { useEffect, useState } from 'react';
import axios from 'axios';
import adminService from '../services/adminService';
import authService from '../services/authService';
import { BarChart, LineChart, PieChart } from '../components/Charts';

export default function AdminDashboard() {
  const [mode, setMode] = useState('local');
  const [loadingMode, setLoadingMode] = useState(true);
  const [changing, setChanging] = useState(false);

  const [users, setUsers] = useState([]);
  const [logs, setLogs] = useState([]);
  const [feedbacks, setFeedbacks] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [loading, setLoading] = useState(false);
  const [evaluations, setEvaluations] = useState([]);
  const [evalSummary, setEvalSummary] = useState([]);
  const [anomalyStats, setAnomalyStats] = useState(null);
  const [activeTab, setActiveTab] = useState('overview');

  const getToken = () => {
    try {
      if (authService && typeof authService.getToken === 'function') return authService.getToken();
      if (authService && authService.default && typeof authService.default.getToken === 'function') return authService.default.getToken();
    } catch (e) {}
    return localStorage.getItem('token');
  };
  const token = getToken();
  const API = process.env.REACT_APP_API_BASE || 'http://localhost:5000';
  const authHeader = { headers: { Authorization: `Bearer ${token}` } };

  // storage-mode helpers
  const fetchStorageMode = async () => {
    try {
      return await adminService.getStorageMode(token);
    } catch (e) {
      console.warn('Failed to fetch storage mode:', e);
      return { mode: 'local' };
    }
  };

  const updateStorageMode = async (m) => {
    try {
      return await adminService.setStorageMode(m, token);
    } catch (e) { 
      throw e; 
    }
  };

  // data fetchers
  const fetchUsers = async () => {
    try {
      const res = await adminService.getUsers(token);
      setUsers(res.users || res || []);
    } catch (e) {
      console.error('fetchUsers', e);
      setUsers([]);
    }
  };

  const fetchLogs = async () => {
    try {
      const res = await adminService.getLogs(token);
      setLogs(res.logs || res || []);
    } catch (e) {
      console.error('fetchLogs', e);
      setLogs([]);
    }
  };

  const fetchFeedbacks = async () => {
    try {
      const res = await adminService.getFeedbacks(token);
      setFeedbacks(res.feedback || res || []);
    } catch (e) {
      console.warn('fetchFeedbacks: missing or failed', e.message || e);
      setFeedbacks([]);
    }
  };

  useEffect(() => {
    let mounted = true;
    (async () => {
      setLoading(true);
      try {
        const r = await fetchStorageMode();
        if (mounted) setMode(r.mode || 'local');
        await Promise.all([fetchUsers(), fetchLogs(), fetchFeedbacks()]);
        await fetchEvaluations();
        // Also fetch evaluation summary and anomaly stats for visualizations
        await Promise.all([fetchEvaluationSummary(), fetchAnomalyStats()]);
        if (mounted) runAnomalyDetection();
      } finally {
        if (mounted) { setLoading(false); setLoadingMode(false); }
      }
    })();
    return () => { mounted = false; };
    // eslint-disable-next-line
  }, [token]);

  // storage toggle
  const toggleStorage = async () => {
    const newMode = mode === 'local' ? 'azure' : 'local';
    setChanging(true);
    try {
      await updateStorageMode(newMode);
      setMode(newMode);
      setNotifications(prev => [{ 
        id: Date.now(), 
        type: 'success', 
        text: `Storage switched to ${newMode.toUpperCase()}` 
      }, ...prev]);
    } catch (e) {
      setNotifications(prev => [{ 
        id: Date.now(), 
        type: 'error', 
        text: `Failed to switch storage: ${e.response?.data?.error || e.message}` 
      }, ...prev]);
    } finally { 
      setChanging(false); 
    }
  };

  // migrate storage with confirmation
  const migrateStorage = async () => {
    const targetMode = mode === 'local' ? 'azure' : 'local';
    const confirmMessage = `This will migrate all existing files from ${mode} to ${targetMode} storage. This may take some time. Continue?`;

    if (!window.confirm(confirmMessage)) return;

    setChanging(true);
    try {
      const result = await adminService.migrateStorage(targetMode, token);
      setMode(targetMode);
      setNotifications(prev => [{ 
        id: Date.now(), 
        type: 'success', 
        text: `Migration completed: ${result.results.migrated} files migrated, ${result.results.failed} failed` 
      }, ...prev]);
    } catch (e) {
      setNotifications(prev => [{ 
        id: Date.now(), 
        type: 'error', 
        text: `Migration failed: ${e.response?.data?.error || e.message}` 
      }, ...prev]);
    } finally { 
      setChanging(false); 
    }
  };

  // User management
  const addUser = async (u) => {
    try {
      await adminService.createUser(u, token);
      await fetchUsers();
      setNotifications(prev => [{ id: Date.now(), type: 'success', text: 'User created' }, ...prev]);
    } catch (e) {
      setNotifications(prev => [{ 
        id: Date.now(), 
        type: 'error', 
        text: `Create user failed: ${e.response?.data?.error || e.message}` 
      }, ...prev]);
    }
  };

  const deleteUser = async (id) => {
    if (!window.confirm('Delete user?')) return;
    try {
      await adminService.deleteUser(id, token);
      setUsers(prev => prev.filter(x => (x.id || x.user_id) !== id));
      setNotifications(prev => [{ id: Date.now(), type: 'warn', text: 'User deleted' }, ...prev]);
    } catch (e) {
      setNotifications(prev => [{ 
        id: Date.now(), 
        type: 'error', 
        text: `Delete failed: ${e.response?.data?.error || e.message}` 
      }, ...prev]);
    }
  };

  // Feedback management
  const replyFeedback = async (id, message) => {
    try {
      await adminService.replyFeedback(id, message, token);
      setFeedbacks(prev => prev.map(f => f.id === id ? { ...f, replied: true } : f));
      setNotifications(prev => [{ id: Date.now(), type: 'success', text: 'Replied to feedback' }, ...prev]);
    } catch (e) {
      setNotifications(prev => [{ 
        id: Date.now(), 
        type: 'error', 
        text: `Reply failed: ${e.response?.data?.error || e.message}` 
      }, ...prev]);
    }
  };

  // Simple client-side anomaly detection
  const runAnomalyDetection = () => {
    const notes = [];
    try {
      logs.forEach(l => {
        const action = String(l.action || l.type || '').toLowerCase();
        if (action.includes('failed') || action.includes('unauthorized') || action.includes('invalid')) {
          notes.push({ id: `anom-${l.id || l.timestamp || Math.random()}`, text: `Suspicious: ${l.user_email || l.user_id || 'user'} - ${l.action || action}`, severity: 'high', log: l });
        }
      });
      const downloads = {};
      logs.forEach(l => {
        const action = String(l.action || l.type || '').toLowerCase();
        if (action.includes('download')) {
          const u = l.user_email || l.user_id || 'unknown';
          downloads[u] = (downloads[u] || 0) + 1;
        }
      });
      Object.entries(downloads).forEach(([u,c]) => { if (c >= 10) notes.push({ id: `anom-dl-${u}`, text: `High downloads by ${u} (${c})`, severity: 'medium' }); });
    } catch (e) {
      console.error('anomaly detection error', e);
    }
    if (notes.length) setNotifications(prev => [...notes, ...prev]);
    return notes;
  };

  const clearNotification = (id) => setNotifications(prev => prev.filter(n => n.id !== id));
  const markAllResolved = () => setNotifications([]);

  // Evaluations
  const fetchEvaluations = async () => {
    try {
      const res = await adminService.getEvaluations(token);
      setEvaluations(res.results || []);
    } catch (e) {
      console.error('fetchEvaluations', e);
      setEvaluations([]);
      setNotifications(prev => [{ id: Date.now(), type: 'error', text: `Failed to load evaluations: ${e.response?.data?.error || e.message}` }, ...prev]);
    }
  };

  // Evaluation summary stats
  const fetchEvaluationSummary = async () => {
    try {
      const res = await adminService.getEvaluationSummary(token);
      setEvalSummary(res.metrics || []);
    } catch (e) {
      console.warn('fetchEvaluationSummary', e.message);
    }
  };

  // Anomaly stats
  const fetchAnomalyStats = async () => {
    try {
      const res = await adminService.getAnomalyStats(token);
      setAnomalyStats(res);
    } catch (e) {
      console.warn('fetchAnomalyStats', e.message);
    }
  };

  // form state for new user
  const [newUser, setNewUser] = useState({ name: '', email: '', password: '', role: 'user' });

  return (
    <div className="p-6 max-w-7xl mx-auto">
      <header className="flex items-start justify-between mb-6">
        <div>
          <h1 className="text-3xl font-bold">Admin Dashboard</h1>
          <p className="text-sm text-gray-500">Manage users, monitor logs, respond to feedback, and control storage.</p>
        </div>

        <div className="space-y-3 text-right">
          <div className="flex items-center gap-3">
            <div className="text-sm text-gray-600">Storage: <span className="font-semibold ml-1">{loadingMode ? '...' : mode.toUpperCase()}</span></div>
            <button onClick={toggleStorage} disabled={changing || loadingMode} className={`px-3 py-1 rounded ${mode==='azure' ? 'bg-blue-600 text-white' : 'bg-gray-200'}`}>
              {changing ? 'Applying...' : (mode === 'azure' ? 'Azure' : 'Local')}
            </button>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={migrateStorage} 
              disabled={changing || loadingMode} 
              className="px-3 py-1 bg-orange-500 text-white rounded text-sm hover:bg-orange-600 disabled:opacity-50"
            >
              {changing ? 'Migrating...' : 'Migrate Files'}
            </button>
            <div className="text-xs text-gray-500">Migrate existing files</div>
          </div>

          <div className="flex gap-2 justify-end">
            <button onClick={() => { fetchUsers(); fetchLogs(); fetchFeedbacks(); }} className="px-3 py-1 bg-white rounded border text-sm">Refresh</button>
            <button onClick={() => { const a = runAnomalyDetection(); if (a.length===0) alert('No anomalies found'); }} className="px-3 py-1 bg-yellow-100 rounded border text-sm">Analyze Logs</button>
            <button onClick={markAllResolved} className="px-3 py-1 bg-green-100 rounded border text-sm">Clear Notifications</button>
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          {/* Users panel */}
          <section className="bg-white p-4 rounded shadow">
            <div className="flex items-center justify-between mb-3">
              <h2 className="font-semibold">Users</h2>
              <div className="text-sm text-gray-500">{users.length} users</div>
            </div>

            <div className="mb-4 grid grid-cols-1 md:grid-cols-3 gap-2">
              <input className="border rounded px-2 py-1" placeholder="Name" value={newUser.name} onChange={e=>setNewUser({...newUser,name:e.target.value})}/>
              <input className="border rounded px-2 py-1" placeholder="Email" value={newUser.email} onChange={e=>setNewUser({...newUser,email:e.target.value})}/>
              <input type="password" className="border rounded px-2 py-1" placeholder="Password" value={newUser.password} onChange={e=>setNewUser({...newUser,password:e.target.value})}/>
              <select className="border rounded px-2 py-1" value={newUser.role} onChange={e=>setNewUser({...newUser,role:e.target.value})}>
                <option value="user">User</option>
                <option value="admin">Admin</option>
              </select>
              <div className="md:col-span-2 flex gap-2">
                <button onClick={() => { if(!newUser.email || !newUser.password) return alert('email & password required'); addUser(newUser); setNewUser({name:'',email:'',password:'',role:'user'}); }} className="px-3 py-1 bg-blue-600 text-white rounded">Add User</button>
                <button onClick={()=>setNewUser({name:'',email:'',password:'',role:'user'})} className="px-3 py-1 bg-gray-100 rounded">Reset</button>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="text-left text-gray-500">
                  <tr><th className="py-2">Name</th><th>Email</th><th>Role</th><th>Actions</th></tr>
                </thead>
                <tbody>
                  {users.map(u => (
                    <tr key={u.id || u.user_id} className="border-t">
                      <td className="py-2">{u.name || '-'}</td>
                      <td>{u.email || '-'}</td>
                      <td>{u.role || 'user'}</td>
                      <td>
                        <button className="text-sm text-red-600" onClick={()=>deleteUser(u.id || u.user_id)}>Delete</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>

          {/* Logs panel */}
          <section className="bg-white p-4 rounded shadow">
            <div className="flex items-center justify-between mb-3">
              <h2 className="font-semibold">Activity Logs</h2>
              <div className="text-sm text-gray-500">{logs.length} entries</div>
            </div>

            <div className="space-y-2 max-h-72 overflow-auto">
              {logs.slice(0,200).map((l, i) => (
                <div key={i} className="flex items-start justify-between bg-gray-50 p-2 rounded">
                  <div>
                    <div className="text-sm font-medium">{l.user_email || l.user || 'Unknown'}</div>
                    <div className="text-xs text-gray-600">{l.action || l.type || l.message || ''}</div>
                    <div className="text-xs text-gray-400">{new Date(l.timestamp || l.created_at || Date.now()).toLocaleString()}</div>
                  </div>
                  <div className="text-xs text-gray-500">{l.file_id ? `File:${l.file_id}` : ''}</div>
                </div>
              ))}
            </div>
          </section>

          {/* Feedback panel */}
          <section className="bg-white p-4 rounded shadow">
            <div className="flex items-center justify-between mb-3">
              <h2 className="font-semibold">User Feedback</h2>
              <div className="text-sm text-gray-500">{feedbacks.length}</div>
            </div>

            <div className="space-y-3">
              {feedbacks.map(f => (
                <div key={f.id} className="border rounded p-3">
                  <div className="flex justify-between items-start">
                    <div>
                      <div className="font-medium">{f.user_email || f.email || 'User'}</div>
                      <div className="text-xs text-gray-600">{new Date(f.created_at || Date.now()).toLocaleString()}</div>
                    </div>
                    <div className="text-sm text-gray-500">{f.replied ? 'Replied' : 'New'}</div>
                  </div>
                  <div className="mt-2 text-sm text-gray-700">{f.message || f.text}</div>
                  <div className="mt-2 flex gap-2">
                    <button onClick={()=>{ const reply = prompt('Reply message'); if(reply) replyFeedback(f.id, reply); }} className="px-2 py-1 bg-blue-600 text-white rounded text-sm">Reply</button>
                  </div>
                </div>
              ))}
              {feedbacks.length === 0 && <div className="text-sm text-gray-400">No feedback yet.</div>}
            </div>
          </section>
        </div>

        {/* Right col: Notifications & summary */}
        <aside className="space-y-6">
          <div className="bg-white p-4 rounded shadow">
            <h3 className="font-semibold mb-2">Notifications</h3>
            <div className="space-y-2 max-h-96 overflow-auto">
              {notifications.length === 0 && <div className="text-sm text-gray-400">No notifications</div>}
              {notifications.map(n => (
                <div key={n.id} className="border rounded p-2 flex justify-between items-start">
                  <div>
                    <div className="text-sm">{n.text}</div>
                    <div className="text-xs text-gray-400">{n.severity || n.type}</div>
                  </div>
                  <div className="flex flex-col items-end gap-1">
                    <button className="text-xs text-green-600" onClick={() => { clearNotification(n.id); }}>Resolve</button>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-white p-4 rounded shadow">
            <h3 className="font-semibold mb-2">Summary</h3>
            <div className="text-sm text-gray-600 space-y-1">
              <div>Total users: <span className="font-medium">{users.length}</span></div>
              <div>Recent logs: <span className="font-medium">{logs.length}</span></div>
              <div>Feedback items: <span className="font-medium">{feedbacks.length}</span></div>
            </div>
          </div>
          <div className="bg-white p-4 rounded shadow">
            <div className="flex items-center justify-between mb-2">
              <h3 className="font-semibold">Evaluations</h3>
              <div className="flex gap-2">
                <button onClick={fetchEvaluations} className="px-2 py-1 bg-blue-600 text-white rounded text-sm">Load</button>
              </div>
            </div>
            <div className="text-xs text-gray-600 mb-2">Showing recent evaluation metrics (timings in ms)</div>
            <div className="max-h-48 overflow-auto text-sm">
              {evaluations.length === 0 && <div className="text-gray-400">No evaluation data yet.</div>}
              {evaluations.slice(0,50).map(ev => (
                <div key={ev.id} className="border-b py-1 flex justify-between">
                  <div>
                    <div className="font-medium">{ev.metric_key}</div>
                    <div className="text-xs text-gray-500">File: {ev.file_id || 'N/A'} • {new Date(ev.created_at).toLocaleString()}</div>
                  </div>
                  <div className="text-right">
                    <div className="font-semibold">{ev.metric_value == null ? '-' : Number(ev.metric_value).toFixed(2)} ms</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </aside>
      </div>

      {/* Visualization Section */}
      <div className="mt-8 space-y-6">
        <div className="bg-gradient-to-r from-blue-50 to-indigo-50 p-6 rounded-lg shadow-md border border-blue-200">
          <div className="flex flex-col lg:flex-row items-start lg:items-center justify-between gap-4 mb-6 border-b-2 border-blue-300 pb-4">
            <div>
              <h2 className="text-3xl font-bold text-gray-800">📊 Evaluation Visualizations</h2>
              <p className="text-sm text-gray-600 mt-1">Monitor system performance and anomaly detection in real-time</p>
            </div>
            <div className="flex gap-2 flex-wrap">
              <button 
                onClick={() => { setActiveTab('metrics'); fetchEvaluationSummary(); }} 
                className={`px-4 py-2 rounded-lg font-medium transition-all ${activeTab === 'metrics' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white text-gray-700 border border-gray-300 hover:bg-gray-50'}`}
              >
                📈 Performance Metrics
              </button>
              <button 
                onClick={() => { setActiveTab('anomaly'); fetchAnomalyStats(); }} 
                className={`px-4 py-2 rounded-lg font-medium transition-all ${activeTab === 'anomaly' ? 'bg-red-600 text-white shadow-lg' : 'bg-white text-gray-700 border border-gray-300 hover:bg-gray-50'}`}
              >
                🔍 Anomaly Detection
              </button>
            </div>
          </div>

          {activeTab === 'metrics' && (
            <div className="space-y-6">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Performance Metrics Bar Chart */}
                {evalSummary.length > 0 ? (
                  <div className="bg-white p-6 rounded-lg shadow border border-gray-200">
                    <BarChart
                      title="⏱️ Average Timing by Operation (ms)"
                      data={evalSummary
                        .filter(m => m.metric_key && !m.metric_key.includes('anomaly'))
                        .map((m, i) => ({
                          label: m.metric_key.replace('_ms', '').replace('_', ' ').substring(0, 12),
                          value: Number(m.avg_value),
                          color: ['#3b82f6', '#ef4444', '#10b981', '#f59e0b', '#8b5cf6'][i % 5]
                        }))}
                      xLabel="Operation Type"
                      yLabel="Time (ms)"
                      maxHeight={250}
                    />
                  </div>
                ) : (
                  <div className="bg-white p-8 rounded-lg shadow border border-gray-200 text-center">
                    <div className="text-gray-400 text-lg">📁 No metrics available</div>
                    <p className="text-sm text-gray-500 mt-2">Upload files to generate performance data</p>
                  </div>
                )}

                {/* Metrics Summary as Pie Chart */}
                {evalSummary.length > 0 && (
                  <div className="bg-white p-6 rounded-lg shadow border border-gray-200">
                    <PieChart
                      title="📊 Operation Count Distribution"
                      data={evalSummary
                        .filter(m => m.metric_key && !m.metric_key.includes('anomaly'))
                        .map((m, i) => ({
                          label: m.metric_key.replace('_ms', '').toUpperCase(),
                          value: m.count || 1
                        }))}
                      maxHeight={280}
                    />
                  </div>
                )}
              </div>

              {/* Performance Summary Stats */}
              <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-4">
                {evalSummary.slice(0, 4).map((metric, i) => (
                  <div key={i} className="bg-white p-4 rounded-lg shadow border-l-4 border-blue-500">
                    <div className="text-xs text-gray-600 uppercase tracking-wide">{metric.metric_key.replace('_ms', '')}</div>
                    <div className="text-2xl font-bold text-blue-600 mt-1">{Number(metric.avg_value).toFixed(1)}</div>
                    <div className="text-xs text-gray-500 mt-2">Avg: {Number(metric.avg_value).toFixed(1)}ms | Min: {Number(metric.min_value).toFixed(1)}ms | Max: {Number(metric.max_value).toFixed(1)}ms</div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'anomaly' && (
            <div className="space-y-6">
              {/* Anomaly Detection Stats */}
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Left: Chart */}
                <div className="lg:col-span-2">
                  {anomalyStats?.logStats && anomalyStats.logStats.length > 0 ? (
                    <div className="bg-white p-6 rounded-lg shadow border border-gray-200">
                      <BarChart
                        title="🚨 Suspicious Activity by Date (Last 7 Days)"
                        data={anomalyStats.logStats.map(stat => ({
                          label: new Date(stat.log_date).toLocaleDateString().substring(0, 5),
                          value: stat.suspicious_count || 0,
                          color: '#ef4444'
                        }))}
                        xLabel="Date"
                        yLabel="Suspicious Logs"
                        maxHeight={280}
                      />
                    </div>
                  ) : (
                    <div className="bg-white p-8 rounded-lg shadow border border-gray-200 text-center">
                      <div className="text-gray-400 text-lg">📭 No anomaly data available</div>
                      <p className="text-sm text-gray-500 mt-2">Run anomaly tests to generate detection data</p>
                    </div>
                  )}
                </div>

                {/* Right: Summary Cards */}
                <div className="space-y-3">
                  {anomalyStats?.logStats && anomalyStats.logStats.length > 0 && (
                    <>
                      <div className="bg-gradient-to-br from-red-50 to-red-100 p-5 rounded-lg border-2 border-red-300 shadow">
                        <div className="flex items-center justify-between">
                          <div>
                            <div className="text-xs text-red-700 font-semibold uppercase">🔴 Suspicious Logs</div>
                            <div className="text-3xl font-bold text-red-600 mt-1">
                              {anomalyStats.logStats.reduce((sum, s) => sum + (s.suspicious_count || 0), 0)}
                            </div>
                          </div>
                        </div>
                      </div>
                      <div className="bg-gradient-to-br from-blue-50 to-blue-100 p-5 rounded-lg border-2 border-blue-300 shadow">
                        <div className="flex items-center justify-between">
                          <div>
                            <div className="text-xs text-blue-700 font-semibold uppercase">📊 Total Logs</div>
                            <div className="text-3xl font-bold text-blue-600 mt-1">
                              {anomalyStats.logStats.reduce((sum, s) => sum + (s.total_logs || 0), 0)}
                            </div>
                          </div>
                        </div>
                      </div>
                      <div className="bg-gradient-to-br from-green-50 to-green-100 p-5 rounded-lg border-2 border-green-300 shadow">
                        <div className="flex items-center justify-between">
                          <div>
                            <div className="text-xs text-green-700 font-semibold uppercase">✓ Status</div>
                            <div className="text-2xl font-bold text-green-600 mt-1">
                              {anomalyStats.logStats.length > 0 ? '🟢 Active' : '⚪ Pending'}
                            </div>
                          </div>
                        </div>
                      </div>
                      <div className="bg-gradient-to-br from-yellow-50 to-yellow-100 p-5 rounded-lg border-2 border-yellow-300 shadow">
                        <div className="flex items-center justify-between">
                          <div>
                            <div className="text-xs text-yellow-700 font-semibold uppercase">⚡ Detection Rate</div>
                            <div className="text-3xl font-bold text-yellow-600 mt-1">
                              {anomalyStats.logStats.length > 0 
                                ? ((anomalyStats.logStats.reduce((sum, s) => sum + (s.suspicious_count || 0), 0) / anomalyStats.logStats.reduce((sum, s) => sum + (s.total_logs || 0), 0) * 100) || 0).toFixed(1)
                                : '0'}%
                            </div>
                          </div>
                        </div>
                      </div>
                    </>
                  )}
                </div>
              </div>

              {/* Run Anomaly Simulation */}
              <div className="bg-gradient-to-r from-yellow-50 to-orange-50 p-6 rounded-lg border-2 border-yellow-400 shadow-md">
                <h3 className="text-lg font-bold text-gray-800 mb-3">🧪 Test Anomaly Detection</h3>
                <p className="text-sm text-gray-700 mb-4">
                  Run a simulation to inject test anomalies and verify detection accuracy:
                </p>
                <div className="bg-gray-900 text-green-400 p-4 rounded font-mono text-xs overflow-x-auto mb-4 border border-gray-700">
                  <div className="mb-2">cd backend</div>
                  <div className="mb-2">node scripts/anomaly_simulation_test.js [mode] [count]</div>
                  <div className="text-gray-500 mb-2">
                    <div># Examples:</div>
                    <div className="text-green-300">node scripts/anomaly_simulation_test.js full 10</div>
                    <div className="text-green-300">node scripts/anomaly_simulation_test.js evaluate</div>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-3 text-xs">
                  <div className="bg-white p-3 rounded border border-gray-300">
                    <strong>📥 inject</strong> - Add simulated anomalies
                  </div>
                  <div className="bg-white p-3 rounded border border-gray-300">
                    <strong>📊 evaluate</strong> - Check detection accuracy
                  </div>
                  <div className="bg-white p-3 rounded border border-gray-300">
                    <strong>🧹 cleanup</strong> - Remove test data
                  </div>
                  <div className="bg-white p-3 rounded border border-gray-300">
                    <strong>🔄 full</strong> - Complete workflow (default)
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
